mapper.select:
SELECT STEP_NO   AS stepNo,
       IS_FINAL  AS isFinal,
       STATUS     AS status
FROM HRTATTENDANCE_APPROVAL01
WHERE REQ_ID            = #{requestId}
  AND COMPANY           = #{company}
  AND APPROVER_EMP_CODE = #{approverEmpCode}
  AND STEP_TYPE         = 'APPROVE'

SELECT COUNT(*)
FROM HRTATTENDANCE_APPROVAL01
WHERE COMPANY = #{company}
  AND REQ_ID = #{requestId}
  AND STEP_TYPE = 'APPROVE'
  AND STEP_NO < #{stepNo}
  AND STATUS <> 'APPROVED'

mapper.update:
UPDATE HRTATTENDANCE_APPROVAL01
SET STATUS      = 'APPROVED',
    DECISION_AT = GETDATE(),
    UPDATED_AT  = GETDATE()
WHERE REQ_ID  = #{requestId}
  AND STEP_NO = #{stepNo}
